const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const files = [
  'AGENTS.md',
  'HEARTBEAT.md',
  'IDENTITY.md',
  'MEMORY.md',
  'SOUL.md',
  'TOOLS.md',
  'USER.md'
];

const results = [];

for (const relPath of files) {
  try {
    const data = fs.readFileSync(relPath);
    const hash = crypto.createHash('sha256').update(data).digest('hex');
    results.push({
      fileName: path.basename(relPath),
      fileType: relPath.includes('memory/') ? '记忆文件' : (relPath.endsWith('.js') ? '脚本文件' : '文档'),
      localPath: relPath,
      backupTime: new Date().toISOString(),
      fileSize: data.length,
      fileHash: 'sha256:' + hash.substring(0, 16) + '...',
      status: '成功',
      remark: '生产验证'
    });
  } catch (e) {
    results.push({
      fileName: path.basename(relPath),
      fileType: '其他',
      localPath: relPath,
      backupTime: new Date().toISOString(),
      fileSize: 0,
      fileHash: 'error',
      status: '失败',
      remark: e.message
    });
  }
}

console.log(JSON.stringify(results, null, 2));

